import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { mount } from '@vue/test-utils'; // assumed dependency
import ViewSwitcher from './ViewSwitcher.vue'; // component to test

describe('ViewSwitcher', () => {
  let wrapper: any;
  const onSwitchMock = vi.fn();

  beforeEach(() => {
    vi.clearAllMocks();
    wrapper = mount(ViewSwitcher, {
      props: {
        viewMode: 'grid',
        onSwitch: onSwitchMock,
      },
    });
  });

  afterEach(() => {
    wrapper.unmount();
  });

  it('should handle happy path when a valid view is selected', async () => {
    const button = wrapper.find('[data-testid="view-mode-grid"]');
    await button.trigger('click');

    expect(onSwitchMock).toHaveBeenCalledTimes(1);
    expect(onSwitchMock).toHaveBeenCalledWith('grid');
  });

  it('should handle edge case when viewMode prop is the default value', async () => {
    wrapper.setProps({ viewMode: 'list' });

    const button = wrapper.find('[data-testid="view-mode-list"]');
    await button.trigger('click');

    expect(onSwitchMock).toHaveBeenCalledTimes(1);
    expect(onSwitchMock).toHaveBeenCalledWith('list');
  });

  it('should handle null/empty values for viewMode and onSwitch', async () => {
    wrapper.unmount();
    const faultyWrapper = mount(ViewSwitcher, {
      props: {
        viewMode: null,
        onSwitch: undefined,
      },
    });

    const button = faultyWrapper.find('[data-testid="view-mode-grid"]');
    await button.trigger('click');

    expect(onSwitchMock).not.toHaveBeenCalled();
    expect(faultyWrapper.exists()).toBe(true);
    faultyWrapper.unmount();
  });
});